use std::error::Error;

trait Processor {
    fn process(&self) -> Result<String, Box<dyn Error>>;
}

struct DocumentProcessor;

impl Processor for DocumentProcessor {
    fn process(&self) -> Result<String, Box<dyn Error>> {
        Ok("Document processed successfully".to_string())
    }
}

struct ImageProcessor;

impl Processor for ImageProcessor {
    fn process(&self) -> Result<String, Box<dyn Error>> {
        Ok("Image resized and watermarked".to_string())
    }
}

fn batch_process<T: Processor>(item: &T) -> Result<String, Box<dyn Error>> {
    item.process()
}

fn main() -> Result<(), Box<dyn Error>> {
    let doc = DocumentProcessor;
    let img = ImageProcessor;

    let result1 = batch_process(&doc);
    println!("Result 1: {}", result1?);

    let result2 = batch_process(&img);
    println!("Result 2: {}", result2?);

    Ok(())
}

use std::fs::File;
use std::io::{self, Read, Write};

struct Processor;

impl Processor {
    fn process_stream<R>(reader: &mut R) -> io::Result<String>
    where
        R: Read,
    {
        let mut buffer = String::new();
        reader.read_to_string(&mut buffer)?;
        Ok(buffer)
    }
}

fn main() -> io::Result<()> {
    let file1 = File::create("test_list.txt")?;
    let file2 = File::create("test_data.txt")?;

    {
        let mut reader = file1;
        let result1 = Processor::process_stream(&mut reader)?;
        println!("Processed List: {}", result1);
    }

    let mut temp_file = File::create("temp.txt")?;
    write!(temp_file, "This is some temporary content.")?; 
    drop(temp_file);

    let file3 = File::open("test_data.txt")?;
    {
        let mut reader = file3;
        let result2 = Processor::process_stream(&mut reader)?;
        println!("Processed Data: {}", result2);
    }

    Ok(())
}

use std::error::Error;

trait Scorable {
    fn get_score(&self) -> i32;
}

struct ItemA { value: i32 } 
impl Scorable for ItemA {
    fn get_score(&self) -> i32 {
        self.value * 2
    }
}

struct ItemB { multiplier: i32 } 
impl Scorable for ItemB {
    fn get_score(&self) -> i32 {
        self.multiplier + 10
    }
}

fn calculate_total<T>(items: &[T]) -> i32 where T: Scorable {
    items.iter().map(|item| item.get_score()).sum()
}

fn main() {
    let list_a = vec![ItemA { value: 5 }, ItemA { value: 10 }];
    let total_a = calculate_total(&list_a);
    println!("Total A: {}", total_a);

    let list_b = vec![ItemB { multiplier: 3 }, ItemB { multiplier: -2 }];
    let total_b = calculate_total(&list_b);
    println!("Total B: {}", total_b);
}

use std::error::Error;

fn process_item<T: std::fmt::Debug>(item: T) -> Result<(), Box<dyn Error>> {
    println!("Processing item that can be shown: {:?}", item);
    Ok(())
}

fn main() {
    let data1 = 42;
    process_item(data1).unwrap();

    let data2 = "Hello World";
    process_item(data2).unwrap();

    struct MyStruct { 
        value: i32
    }
    let data3 = MyStruct { value: 99 };
    process_item(data3).unwrap();
}

use std::fmt::Write;

struct Processor;

impl Write for Processor {
    fn write_str(&mut self, s: &str) -> Result<(), std::fmt::Error> {
        write!(self, "{}", s)
    }
}

fn process_items<T>(item: T) -> String
where
    T: std::fmt::Write + 'static,
{
    let mut buffer = String::new();
    writeln!(&mut buffer, "Processing item of type that can write to string...")
        .unwrap();
    write!( &mut buffer, "nSuccessfully handled the input.")
        .unwrap();
    buffer
}

fn main() {
    let p1 = Processor;
    let result1 = process_items(p1);
    println!("n--- Result 1 ---n{}", result1);

    struct SimpleData {}

    impl std::fmt::Write for SimpleData {
        fn write_str(&mut self, s: &str) -> Result<(), std::fmt::Error> {
            write!(self, "{}", s)
        }
    }

    let p2 = SimpleData {};
    let result2 = process_items(p2);
    println!("n--- Result 2 ---n{}", result2);
}
